namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAtUtc { get; set; }
    public DateTime? EstimatedDeliveryUtc { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string CustomerEmail { get; set; } = string.Empty;
    public string? Notes { get; set; }
}

public class UpdateShipmentStatusRequest
{
    public ShipmentStatus NewStatus { get; set; }
    public string? Notes { get; set; }
}

using System.ComponentModel.DataAnnotations;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }

    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public ShipmentStatus Status { get; set; }

    public DateTime CreatedAtUtc { get; set; }

    public DateTime? EstimatedDeliveryUtc { get; set; }

    [MaxLength(150)]
    public string RecipientName { get; set; } = string.Empty;

    [MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;

    [MaxLength(500)]
    public string? Notes { get; set; }

    public ShipmentDto ToDto() => new()
    {
        Id = Id,
        TrackingNumber = TrackingNumber,
        Origin = Origin,
        Destination = Destination,
        Status = Status,
        CreatedAtUtc = CreatedAtUtc,
        EstimatedDeliveryUtc = EstimatedDeliveryUtc,
        RecipientName = RecipientName,
        CustomerEmail = CustomerEmail,
        Notes = Notes
    };
}

