using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers) or only own shipments (customers)
        group.MapGet("/", async (ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext ctx) =>
        {
            var user = await userManager.GetUserAsync(ctx.User);
            if (user is null) return Results.Unauthorized();

            IQueryable<Shipment> query = db.Shipments.OrderByDescending(s => s.CreatedAtUtc);
            if (user.Role != "Dispatcher")
            {
                query = query.Where(s => s.CustomerEmail == user.Email);
            }

            var shipments = await query.Select(s => s.ToDto()).ToListAsync();
            return Results.Ok(shipments);
        });

        // Get single shipment by tracking number
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext ctx) =>
        {
            var user = await userManager.GetUserAsync(ctx.User);
            if (user is null) return Results.Unauthorized();

            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            if (shipment is null) return Results.NotFound();

            if (user.Role != "Dispatcher" && shipment.CustomerEmail != user.Email)
                return Results.Forbid();

            return Results.Ok(shipment.ToDto());
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext ctx) =>
        {
            var user = await userManager.GetUserAsync(ctx.User);
            if (user is null) return Results.Unauthorized();
            if (user.Role != "Dispatcher") return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.NewStatus;
            if (request.Notes is not null) shipment.Notes = request.Notes;

            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        });

        // Create shipment (dispatchers only)
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db, UserManager<ApplicationUser> userManager, HttpContext ctx) =>
        {
            var user = await userManager.GetUserAsync(ctx.User);
            if (user is null) return Results.Unauthorized();
            if (user.Role != "Dispatcher") return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = ShipmentStatus.Pending,
                CreatedAtUtc = DateTime.UtcNow,
                EstimatedDeliveryUtc = dto.EstimatedDeliveryUtc,
                RecipientName = dto.RecipientName,
                CustomerEmail = dto.CustomerEmail,
                Notes = dto.Notes
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", shipment.ToDto());
        });
    }
}

