@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>📦 Dispatcher Dashboard</h2>

<AuthorizeView>
    <Authorized>
        @if (!IsDispatcher(context))
        {
            <div class="alert alert-warning">
                <strong>Access Denied.</strong> This page is for dispatchers only.
            </div>
        }
        else
        {
            <div class="row mb-3">
                <div class="col-md-4">
                    <input type="text" class="form-control" placeholder="Filter by destination..."
                           @bind="filterText" @bind:event="oninput" />
                </div>
                <div class="col-md-3">
                    <select class="form-select" @bind="statusFilter">
                        <option value="">All Statuses</option>
                        @foreach (var s in Enum.GetValues<ShipmentStatus>())
                        {
                            <option value="@s">@s</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <button class="btn btn-primary" @onclick="LoadShipments">
                        🔄 Refresh
                    </button>
                    <button class="btn btn-success ms-2" @onclick="ShowCreateForm">
                        ➕ New Shipment
                    </button>
                </div>
            </div>

            @if (showCreateForm)
            {
                <div class="card mb-3">
                    <div class="card-body">
                        <h5>Create New Shipment</h5>
                        <div class="row g-2">
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Tracking #" @bind="newShipment.TrackingNumber" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Recipient Name" @bind="newShipment.RecipientName" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                            </div>
                            <div class="col-md-3">
                                <label class="form-label small">Estimated Delivery (UTC)</label>
                                <input type="datetime-local" class="form-control" @bind="estimatedDelivery" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Notes" @bind="newShipment.Notes" />
                            </div>
                            <div class="col-md-3 d-flex align-items-end">
                                <button class="btn btn-primary me-2" @onclick="CreateShipment">Create</button>
                                <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                            </div>
                        </div>
                        @if (createError is not null)
                        {
                            <div class="alert alert-danger mt-2">@createError</div>
                        }
                    </div>
                </div>
            }

            @if (loading)
            {
                <p><em>Loading shipments...</em></p>
            }
            else if (shipments is null)
            {
                <div class="alert alert-danger">Failed to load shipments.</div>
            }
            else
            {
                <table class="table table-striped table-hover">
                    <thead class="table-dark">
                        <tr>
                            <th>Tracking #</th>
                            <th>Origin</th>
                            <th>Destination</th>
                            <th>Status</th>
                            <th>Recipient</th>
                            <th>Est. Delivery</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var s in FilteredShipments)
                        {
                            <tr>
                                <td><code>@s.TrackingNumber</code></td>
                                <td>@s.Origin</td>
                                <td>@s.Destination</td>
                                <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                                <td>@s.RecipientName</td>
                                <td>@(s.EstimatedDeliveryUtc?.ToString("MMM dd, yyyy") ?? "—")</td>
                                <td>
                                    <select class="form-select form-select-sm d-inline-block w-auto"
                                            @onchange="e => UpdateStatus(s.Id, e)">
                                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                        {
                                            <option value="@status" selected="@(status == s.Status)">@status</option>
                                        }
                                    </select>
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
                <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
            }
        }
    </Authorized>
</AuthorizeView>

@code {
    private List<ShipmentDto>? shipments;
    private bool loading = true;
    private string filterText = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDelivery;
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
        }
        catch
        {
            shipments = null;
        }
        loading = false;
    }

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) ||
             s.Status.ToString() == statusFilter));

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var request = new UpdateShipmentStatusRequest { NewStatus = newStatus };
            await Http.PutAsJsonAsync($"/api/shipments/{id}/status", request);
            await LoadShipments();
        }
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new ShipmentDto { TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMddHHmmss}" };
        estimatedDelivery = DateTime.UtcNow.AddDays(5);
        createError = null;
    }

    private async Task CreateShipment()
    {
        createError = null;
        newShipment.EstimatedDeliveryUtc = estimatedDelivery;
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreateForm = false;
            await LoadShipments();
        }
        else
        {
            createError = $"Failed to create shipment: {response.StatusCode}";
        }
    }

    private static bool IsDispatcher(AuthenticationState context) =>
        context.User.FindFirst("user_role")?.Value == "Dispatcher";

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/tracking"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Track Your Shipment</PageTitle>

<h2>🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. TRK-20260001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment">
                Track
            </button>
        </div>
    </div>
</div>

@if (searching)
{
    <p><em>Searching...</em></p>
}
else if (searchPerformed && trackedShipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>.
        Please check the number and try again.
    </div>
}
else if (trackedShipment is not null)
{
    <div class="card shadow-sm">
        <div class="card-header bg-dark text-white">
            <h5 class="mb-0">Shipment <code class="text-light">@trackedShipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @StatusBadgeClass(trackedShipment.Status) fs-6">@trackedShipment.Status</span></dd>

                        <dt>Origin</dt>
                        <dd>@trackedShipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@trackedShipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Recipient</dt>
                        <dd>@trackedShipment.RecipientName</dd>

                        <dt>Shipped</dt>
                        <dd>@trackedShipment.CreatedAtUtc.ToString("MMMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (trackedShipment.EstimatedDeliveryUtc.HasValue)
                            {
                                var daysLeft = (trackedShipment.EstimatedDeliveryUtc.Value - DateTime.UtcNow).Days;
                                <span>@trackedShipment.EstimatedDeliveryUtc.Value.ToString("MMMM dd, yyyy")</span>
                                @if (trackedShipment.Status != ShipmentStatus.Delivered && trackedShipment.Status != ShipmentStatus.Cancelled)
                                {
                                    if (daysLeft > 0)
                                    {
                                        <span class="text-muted ms-2">(@daysLeft day(s) remaining)</span>
                                    }
                                    else if (daysLeft == 0)
                                    {
                                        <span class="text-success ms-2">(Arriving today!)</span>
                                    }
                                    else
                                    {
                                        <span class="text-danger ms-2">(Delayed)</span>
                                    }
                                }
                            }
                            else
                            {
                                <span class="text-muted">Not yet estimated</span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(trackedShipment.Notes))
            {
                <div class="alert alert-info mt-2">
                    <strong>Notes:</strong> @trackedShipment.Notes
                </div>
            }

            <!-- Progress visualization -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @ProgressBarClass(trackedShipment.Status)"
                         style="width: @ProgressPercent(trackedShipment.Status)%">
                        @trackedShipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<hr class="my-4" />

<h4>Your Shipments</h4>

@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments.Count == 0)
{
    <p class="text-muted">You have no shipments yet.</p>
}
else
{
    <div class="row">
        @foreach (var s in myShipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100 @(s.Status == ShipmentStatus.Delivered ? "border-success" : "")">
                    <div class="card-body">
                        <h6 class="card-title">
                            <code>@s.TrackingNumber</code>
                            <span class="badge @StatusBadgeClass(s.Status) float-end">@s.Status</span>
                        </h6>
                        <p class="card-text small">
                            <strong>To:</strong> @s.Destination<br />
                            <strong>Recipient:</strong> @s.RecipientName<br />
                            @if (s.EstimatedDeliveryUtc.HasValue)
                            {
                                <strong>ETA:</strong> @s.EstimatedDeliveryUtc.Value.ToString("MMM dd, yyyy")
                            }
                        </p>
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => TrackSpecific(s.TrackingNumber)">
                            View Details
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;
    private bool searching;
    private bool searchPerformed;

    protected override async Task OnInitializedAsync()
    {
        await LoadMyShipments();
    }

    private async Task LoadMyShipments()
    {
        try
        {
            myShipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
        }
        catch
        {
            myShipments = [];
        }
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        searching = true;
        searchPerformed = false;
        trackedShipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{trackingNumber.Trim()}");
            if (response.IsSuccessStatusCode)
            {
                trackedShipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
        }
        catch { }

        searchedNumber = trackingNumber.Trim();
        searchPerformed = true;
        searching = false;
    }

    private async Task TrackSpecific(string tn)
    {
        trackingNumber = tn;
        await TrackShipment();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await TrackShipment();
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static int ProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string ProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };
}

