@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>📦 Dispatcher Dashboard</h2>

<AuthorizeView>
    <Authorized>
        @if (!IsDispatcher(context))
        {
            <div class="alert alert-warning">
                <strong>Access Denied.</strong> This page is for dispatchers only.
            </div>
        }
        else
        {
            <div class="row mb-3">
                <div class="col-md-4">
                    <input type="text" class="form-control" placeholder="Filter by destination..."
                           @bind="filterText" @bind:event="oninput" />
                </div>
                <div class="col-md-3">
                    <select class="form-select" @bind="statusFilter">
                        <option value="">All Statuses</option>
                        @foreach (var s in Enum.GetValues<ShipmentStatus>())
                        {
                            <option value="@s">@s</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <button class="btn btn-primary" @onclick="LoadShipments">
                        🔄 Refresh
                    </button>
                    <button class="btn btn-success ms-2" @onclick="ShowCreateForm">
                        ➕ New Shipment
                    </button>
                </div>
            </div>

            @if (showCreateForm)
            {
                <div class="card mb-3">
                    <div class="card-body">
                        <h5>Create New Shipment</h5>
                        <div class="row g-2">
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Tracking #" @bind="newShipment.TrackingNumber" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Recipient Name" @bind="newShipment.RecipientName" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                            </div>
                            <div class="col-md-3">
                                <label class="form-label small">Estimated Delivery (UTC)</label>
                                <input type="datetime-local" class="form-control" @bind="estimatedDelivery" />
                            </div>
                            <div class="col-md-3">
                                <input class="form-control" placeholder="Notes" @bind="newShipment.Notes" />
                            </div>
                            <div class="col-md-3 d-flex align-items-end">
                                <button class="btn btn-primary me-2" @onclick="CreateShipment">Create</button>
                                <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                            </div>
                        </div>
                        @if (createError is not null)
                        {
                            <div class="alert alert-danger mt-2">@createError</div>
                        }
                    </div>
                </div>
            }

            @if (loading)
            {
                <p><em>Loading shipments...</em></p>
            }
            else if (shipments is null)
            {
                <div class="alert alert-danger">Failed to load shipments.</div>
            }
            else
            {
                <table class="table table-striped table-hover">
                    <thead class="table-dark">
                        <tr>
                            <th>Tracking #</th>
                            <th>Origin</th>
                            <th>Destination</th>
                            <th>Status</th>
                            <th>Recipient</th>
                            <th>Est. Delivery</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var s in FilteredShipments)
                        {
                            <tr>
                                <td><code>@s.TrackingNumber</code></td>
                                <td>@s.Origin</td>
                                <td>@s.Destination</td>
                                <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                                <td>@s.RecipientName</td>
                                <td>@(s.EstimatedDeliveryUtc?.ToString("MMM dd, yyyy") ?? "—")</td>
                                <td>
                                    <select class="form-select form-select-sm d-inline-block w-auto"
                                            @onchange="e => UpdateStatus(s.Id, e)">
                                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                        {
                                            <option value="@status" selected="@(status == s.Status)">@status</option>
                                        }
                                    </select>
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
                <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
            }
        }
    </Authorized>
</AuthorizeView>

@code {
    private List<ShipmentDto>? shipments;
    private bool loading = true;
    private string filterText = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDelivery;
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
        }
        catch
        {
            shipments = null;
        }
        loading = false;
    }

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrEmpty(filterText) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrEmpty(statusFilter) ||
             s.Status.ToString() == statusFilter));

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var request = new UpdateShipmentStatusRequest { NewStatus = newStatus };
            await Http.PutAsJsonAsync($"/api/shipments/{id}/status", request);
            await LoadShipments();
        }
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new ShipmentDto { TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMddHHmmss}" };
        estimatedDelivery = DateTime.UtcNow.AddDays(5);
        createError = null;
    }

    private async Task CreateShipment()
    {
        createError = null;
        newShipment.EstimatedDeliveryUtc = estimatedDelivery;
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showCreateForm = false;
            await LoadShipments();
        }
        else
        {
            createError = $"Failed to create shipment: {response.StatusCode}";
        }
    }

    private static bool IsDispatcher(AuthenticationState context) =>
        context.User.FindFirst("user_role")?.Value == "Dispatcher";

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

