+            (string.IsNullOrEmpty(statusFilter) ||
+             s.Status.ToString() == statusFilter));
+
+    private async Task UpdateStatus(int id, ChangeEventArgs e)
+    {
+        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
+        {
+            var request = new UpdateShipmentStatusRequest { NewStatus = newStatus };
+            await Http.PutAsJsonAsync($"/api/shipments/{id}/status", request);
+            await LoadShipments();
+        }
+    }
+
+    private void ShowCreateForm()
+    {
+        showCreateForm = true;
+        newShipment = new ShipmentDto { TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMddHHmmss}" };
+        estimatedDelivery = DateTime.UtcNow.AddDays(5);
+        createError = null;
+    }
+
+    private async Task CreateShipment()
+    {
+        createError = null;
+        newShipment.EstimatedDeliveryUtc = estimatedDelivery;
+        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
+        if (response.IsSuccessStatusCode)
+        {
+            showCreateForm = false;
+            await LoadShipments();
+        }
+        else
+        {
+            createError = $"Failed to create shipment: {response.StatusCode}";
+        }
+    }
+
+    private static bool IsDispatcher(AuthenticationState context) =>
+        context.User.FindFirst("user_role")?.Value == "Dispatcher";
+
+    private static string StatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Pending => "bg-secondary",
